/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   SHARED UTILITIES
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
AM.util = {
  /**
   * Escape HTML special characters to prevent XSS.
   * @param {string} str - Raw string
   * @returns {string} Safe HTML string
   */
  escapeHtml(str) {
    if (str == null) return '';
    const s = String(str);
    const map = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' };
    return s.replace(/[&<>"']/g, ch => map[ch]);
  },

  /**
   * Box-Muller normal random. Defined ONCE, used everywhere.
   * @returns {number} Standard normal variate
   */
  randn() {
    let u = 0, v = 0;
    while (u === 0) u = Math.random();
    while (v === 0) v = Math.random();
    return Math.sqrt(-2.0 * Math.log(u)) * Math.cos(2.0 * Math.PI * v);
  },

  /**
   * Format a number with locale and decimal control.
   * @param {number} n
   * @param {number} [decimals=2]
   * @returns {string}
   */
  formatNumber(n, decimals) {
    if (decimals === undefined) decimals = 2;
    return Number(n).toLocaleString('fr-FR', {
      minimumFractionDigits: decimals,
      maximumFractionDigits: decimals,
    });
  },

  /**
   * Format a currency value.
   * @param {number} n
   * @param {string} [currency='$']
   * @returns {string}
   */
  formatCurrency(n, currency) {
    if (!currency) currency = '$';
    return currency + AM.util.formatNumber(n, 0);
  },

  /**
   * Format as a percentage string.
   * @param {number} n
   * @returns {string}
   */
  formatPercent(n) {
    const sign = n >= 0 ? '+' : '';
    return sign + n.toFixed(2) + '%';
  },

  /**
   * Debounce utility.
   * @param {Function} fn
   * @param {number} ms
   * @returns {Function}
   */
  debounce(fn, ms) {
    let timer;
    return function() {
      const args = arguments;
      const ctx = this;
      clearTimeout(timer);
      timer = setTimeout(function() { fn.apply(ctx, args); }, ms);
    };
  },
};


/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   CHART MANAGEMENT
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
AM.charts = {
  _instances: {},

  /**
   * Create (or recreate) a Chart.js chart.
   * Automatically destroys existing chart on same id.
   * @param {string} id - Canvas element id
   * @param {object} config - Chart.js config
   * @returns {Chart|null}
   */
  create(id, config) {
    if (typeof Chart === 'undefined') return null;
    const canvas = document.getElementById(id);
    if (!canvas) return null;
    AM.charts.destroy(id);
    try {
      var instance = new Chart(canvas, config);
      AM.charts._instances[id] = instance;
      return instance;
    } catch (e) {
      console.warn('[AM.charts] Erreur création chart "' + id + '":', e.message);
      return null;
    }
  },

  /**
   * Safely destroy a chart by canvas id.
   * @param {string} id
   */
  destroy(id) {
    var c = AM.charts._instances[id];
    if (c) {
      try { c.destroy(); } catch (e) { /* swallow */ }
      delete AM.charts._instances[id];
    }
  },

  /**
   * Destroy all tracked chart instances.
   */
  destroyAll() {
    Object.keys(AM.charts._instances).forEach(function(id) {
      AM.charts.destroy(id);
    });
  },

  /**
   * Shared dark theme defaults for Chart.js line/bar charts.
   */
  darkTheme: {
    gridColor: '#222',
    tickColor: '#666',
    legendColor: '#888',
    legendFont: { size: 10 },
    titleColor: '#ff9800',
    titleFont: { size: 13 },
    scales: {
      x: {
        grid: { color: '#222' },
        ticks: { color: '#666' },
      },
      y: {
        grid: { color: '#222' },
        ticks: { color: '#666' },
      },
    },
  },

  /**
   * Build a clean Chart.js options object from darkTheme.
   * @param {object} [overrides] - Additional Chart.js options to merge
   * @returns {object} Chart.js options
   */
  darkOpts: function(overrides) {
    var dt = AM.charts.darkTheme;
    var base = {
      responsive: true,
      maintainAspectRatio: false,
      animation: { duration: 300 },
      plugins: {
        legend: { labels: { color: dt.legendColor, font: dt.legendFont } },
      },
      scales: {
        x: { grid: { color: dt.gridColor }, ticks: { color: dt.tickColor } },
        y: { grid: { color: dt.gridColor }, ticks: { color: dt.tickColor } },
      },
    };
    if (!overrides) return base;
    // Shallow merge with special handling for nested objects
    var result = Object.assign({}, base, overrides);
    if (overrides.plugins) {
      result.plugins = Object.assign({}, base.plugins, overrides.plugins);
    }
    if (overrides.scales) {
      result.scales = Object.assign({}, base.scales, overrides.scales);
    }
    return result;
  },
};


/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   UI COMPONENT HELPERS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
AM.ui = {
  /**
   * Universal KPI card renderer.
   * @param {string} label
   * @param {string} value
   * @param {string} [sub]
   * @param {object} [options] - { accent, borderColor, valueColor }
   * @returns {string} HTML
   */
  kpi(label, value, sub, options) {
    var o = options || {};
    var cls = 'kpi-card' + (o.accent ? ' kpi-accent' : '');
    var borderStyle = o.borderColor ? 'border-top:3px solid ' + AM.util.escapeHtml(o.borderColor) + ';' : '';
    var valStyle = o.valueColor ? 'color:' + AM.util.escapeHtml(o.valueColor) + ';' : '';
    var html = '<div class="' + cls + '" style="' + borderStyle + '">';
    html += '<div class="kpi-label">' + AM.util.escapeHtml(label) + '</div>';
    html += '<div class="kpi-val" style="' + valStyle + '">' + AM.util.escapeHtml(value) + '</div>';
    if (sub) {
      html += '<div class="kpi-sub">' + AM.util.escapeHtml(sub) + '</div>';
    }
    html += '</div>';
    return html;
  },

  /**
   * Badge renderer.
   * @param {string} text
   * @param {string} type - 'up', 'dn', 'or', 'bl'
   * @returns {string} HTML
   */
  badge(text, type) {
    return '<span class="badge badge-' + AM.util.escapeHtml(type) + '">'
      + AM.util.escapeHtml(text) + '</span>';
  },

  /**
   * Card wrapper.
   * @param {string} content - inner HTML (trusted)
   * @param {object} [options] - { style }
   * @returns {string} HTML
   */
  card(content, options) {
    var o = options || {};
    var style = o.style ? ' style="' + AM.util.escapeHtml(o.style) + '"' : '';
    return '<div class="card"' + style + '>' + content + '</div>';
  },
};


