      '\ud83c\uddeb\ud83c\uddf7 France':     { banque: 'BCE',  actuel: 2.00, precedent: 2.25, reunion: '30 Avr 2026', historique: [4.50, 4.25, 3.65, 3.15, 2.65, 2.40, 2.15, 2.00, 2.00, 2.00, 2.25, 2.00] },
      '\ud83c\udde8\ud83c\uddf3 Chine':      { banque: 'PBOC', actuel: 3.10, precedent: 3.35, reunion: 'Avr 2026',  historique: [3.45, 3.45, 3.35, 3.35, 3.35, 3.10, 3.10, 3.10, 3.10, 3.10, 3.35, 3.10] },
