      '\ud83c\uddef\ud83c\uddf5 Japon':      { actuel: 249.7, precedent: 255.2, historique: [234.2, 250.5, 261.3, 255.2, 255.2, 249.7] },
      '\ud83c\uddec\ud83c\udde7 UK':         { actuel: 99.4,  precedent: 97.8,  historique: [85.2, 95.3, 101.9, 97.8, 97.8, 99.4] },
