  /** Get all commodities flat */
  getAll: function() {
    if (!AM.mp._all) {
      AM.mp._all = [];
      Object.keys(AM.mp.MP_DATA).forEach(function(cat) {
        AM.mp.MP_DATA[cat].forEach(function(item) {
          AM.mp._all.push(item);
        });
      });
    }
    return AM.mp._all;
  },

