function _getAnalyseurData(sym) {
  /* Cherche la correspondance exacte, puis par ticker court */
  if (ANALYSEUR_DB[sym]) return ANALYSEUR_DB[sym];
  /* Fallback générique basé sur le ticker */
  var ticker = sym.split(':').pop();
  var generic = {
    name: ticker, signal: 'NEUTRE ➡', signalColor: 'var(--yellow)', signalScore: '+5 / 9 indicateurs',
    rsi: '50.0', rsiLabel: 'Zone neutre', rsiColor: 'var(--yellow)',
    macd: 'Neutre ⟶', macdColor: 'var(--yellow)', macdSub: '±0.00 vs signal',
    boll: '50%', bollSub: 'Milieu des bandes',
    trend: { ma20:'⟶ Sur la MA', ma20c:'var(--yellow)', ma50:'⟶ Sur la MA', ma50c:'var(--yellow)', ma200:'⟶ Sur la MA', ma200c:'var(--yellow)', gc:'⚠ Inactif', gcc:'' },
    momentum: { rsi:'50.0 – Neutre', rsic:'var(--yellow)', macd:'Neutre ⟶', macdc:'var(--yellow)', stoch:'50 – Neutre', stochc:'var(--yellow)', cci:'0 – Neutre', ccic:'var(--yellow)' },
    volat: { boll:'50% – Milieu', atr:'—', atrc:'var(--orange)', vol:'Normal', volc:'var(--yellow)', vix:'Modéré', vixc:'var(--yellow)' },
    verdict: { sf:2, ac:3, ne:4, ve:2, pct:50 },
    fund: {
      pe:'—', peg:'—', pegc:'', pb:'—', mc:'—',
      eps:'—', epsc:'', rev:'—', revc:'', marge:'—', margec:'', roe:'—', roec:'',
      beta:'—', betac:'var(--yellow)', hi52:'—', lo52:'—'
    },
    news: [
      { col:'var(--tx-muted)', src:'Info', title:'Données spécifiques à ' + ticker + ' non disponibles dans la base locale. Utilisez TradingView pour l\'analyse en temps réel.', time:'Maintenant' }
    ]
  };
  return generic;
}

function _renderSignalClass(c) {
  if (c === 'up') return 'class="up"';
  if (c === 'dn') return 'class="dn"';
  return 'style="color:' + c + ';"';
}


function tvNormalizeSym(sym) {
  if (!sym) return sym;
  /* Déjà préfixé autrement qu'EURONEXT → intact */
  if (sym.indexOf(':') !== -1 && sym.indexOf('EURONEXT:') !== 0) return sym;

  /* Extraire le ticker brut */
  var t = sym.indexOf('EURONEXT:') === 0 ? sym.slice(9) : sym;
  /* Format .PA → extraire le ticker */
  if (t.match(/^[A-Z0-9]+\.PA$/)) t = t.replace('.PA','');

  /* Map EURONEXT ticker → XETR ticker (vérifiés sur TradingView) */
  var MAP = {
    /* Luxe */
    'MC':'MOH', 'RMS':'HMI', 'KER':'KER',
    /* Energie */
    'TTE':'TOTB',
    /* Industrie / Aero */
    'AIR':'AIR', 'SU':'SU', 'SGO':'SGO', 'VIE':'VIE',
    /* Pharma / Sante */
    'SAN':'SNW',
    /* Banque / Assurance */
    'BNP':'BNP', 'ACA':'ACA', 'CS':'CS', 'SG':'SGE',
    /* Conso */
    'OR':'LOR', 'BN':'BN', 'RI':'RI',
    /* Tech */
    'CAP':'CAP', 'DSY':'DSY',
    /* Industrie */
    'AI':'AIL', 'ML':'ML', 'HO':'THO',
    /* Telecom */
    'ORA':'ORA',
    /* Auto */
    'RNO':'RNO', 'STLA':'STLA',
    /* Semi */
    'STM':'STM',
    /* Autres */
    'EN':'EN', 'EL':'EL', 'PUB':'PUBG', 'URW':'URW',
    /* Index CAC 40 */
    'PX1':'CAC40'
  };

  var xetrTicker = MAP[t] || t;
  return 'XETR:' + xetrTicker;
}

function tvReloadStock(id) {
  var sym   = ((document.getElementById(id+'-sym')  ||{}).value || 'NASDAQ:NVDA').toUpperCase().trim();
  var tf    = (document.getElementById(id+'-tf')    ||{}).value || 'D';
  var style = (document.getElementById(id+'-style') ||{}).value || '1';
  var frame = document.getElementById(id+'-frame');
  if (!frame) return;

  /* 1. Mettre à jour le graphique TradingView */
  var tvSym = tvNormalizeSym(sym);
  frame.src = 'https://www.tradingview.com/widgetembed/?symbol=' + encodeURIComponent(tvSym)
    + '&interval=' + tf + '&theme=dark&style=' + style
    + '&locale=fr&timezone=Europe%2FParis&allow_symbol_change=1&withdateranges=1'
    + '&studies=RSI%400%2CMACD%400%2CVolume%400';

  /* 2. Récupérer les données du ticker */
  if (id !== 'analyseur') return; /* Sécurité : ne s'applique qu'à l'analyseur */
  var d = _getAnalyseurData(sym);

  /* 3. Mettre à jour les KPI cards (via IDs fixes) */
  var el;
  el = document.getElementById('an-kpi-signal-val');
  if (el) { el.textContent = d.signal; el.style.color = d.signalColor; }
  el = document.getElementById('an-kpi-signal-sub');
  if (el) el.textContent = d.signalScore;
  el = document.getElementById('an-kpi-rsi-val');
  if (el) { el.textContent = d.rsi; el.style.color = d.rsiColor; }
  el = document.getElementById('an-kpi-rsi-sub');
  if (el) el.textContent = d.rsiLabel;
  el = document.getElementById('an-kpi-macd-val');
  if (el) { el.textContent = d.macd; el.style.color = d.macdColor; }
  el = document.getElementById('an-kpi-macd-sub');
  if (el) el.textContent = d.macdSub;
  el = document.getElementById('an-kpi-boll-val');
  if (el) el.textContent = d.boll;
  el = document.getElementById('an-kpi-boll-sub');
  if (el) el.textContent = d.bollSub;

  /* 4. Mettre à jour le panel Signaux (#an-sig) */
  var sigPanel = document.getElementById('an-sig');
  if (sigPanel) {
    var t = d.trend, m = d.momentum, v = d.volat, vd = d.verdict;
    sigPanel.innerHTML =
      '<div style="display:flex;flex-direction:column;gap:8px;">'
      /* TENDANCE */
      +'<div class="card" style="padding:12px;">'
      +'<div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:var(--orange);font-family:var(--mono);font-weight:700;margin-bottom:8px;">TENDANCE</div>'
      +'<div style="font-size:11px;font-family:var(--mono);">'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">MA 20</span><span '+_renderSignalClass(t.ma20c)+'>'+t.ma20+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">MA 50</span><span '+_renderSignalClass(t.ma50c)+'>'+t.ma50+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">MA 200</span><span '+_renderSignalClass(t.ma200c)+'>'+t.ma200+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;"><span style="color:var(--tx-muted);">Golden/Death Cross</span><span '+_renderSignalClass(t.gcc)+'>'+t.gc+'</span></div>'
      +'</div></div>'
      /* MOMENTUM */
      +'<div class="card" style="padding:12px;">'
      +'<div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:var(--orange);font-family:var(--mono);font-weight:700;margin-bottom:8px;">MOMENTUM</div>'
      +'<div style="font-size:11px;font-family:var(--mono);">'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">RSI (14)</span><span style="color:'+m.rsic+';">'+m.rsi+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">MACD</span><span '+_renderSignalClass(m.macdc)+'>'+m.macd+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">Stochastique</span><span '+_renderSignalClass(m.stochc)+'>'+m.stoch+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;"><span style="color:var(--tx-muted);">CCI (20)</span><span '+_renderSignalClass(m.ccic)+'>'+m.cci+'</span></div>'
      +'</div></div>'
      /* VOLATILITÉ */
      +'<div class="card" style="padding:12px;">'
      +'<div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:var(--orange);font-family:var(--mono);font-weight:700;margin-bottom:8px;">VOLATILITÉ</div>'
      +'<div style="font-size:11px;font-family:var(--mono);">'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">Bollinger</span><span>'+v.boll+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">ATR (14)</span><span style="color:'+v.atrc+';">'+v.atr+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">Volume vs MA</span><span '+_renderSignalClass(v.volc)+'>'+v.vol+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:4px 0;"><span style="color:var(--tx-muted);">VIX Impact</span><span style="color:'+v.vixc+';">'+v.vix+'</span></div>'
      +'</div></div>'
      /* VERDICT */
      +'<div class="card" style="padding:12px;">'
      +'<div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:var(--orange);font-family:var(--mono);font-weight:700;margin-bottom:8px;">VERDICT</div>'
      +'<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:6px;text-align:center;font-family:var(--mono);">'
      +'<div><div style="font-size:16px;font-weight:700;color:var(--green);">'+vd.sf+'</div><div style="font-size:9px;color:var(--tx-faint);">Achat Fort</div></div>'
      +'<div><div style="font-size:16px;font-weight:700;color:#44cc88;">'+vd.ac+'</div><div style="font-size:9px;color:var(--tx-faint);">Achat</div></div>'
      +'<div><div style="font-size:16px;font-weight:700;color:var(--yellow);">'+vd.ne+'</div><div style="font-size:9px;color:var(--tx-faint);">Neutre</div></div>'
      +'<div><div style="font-size:16px;font-weight:700;color:var(--red);">'+vd.ve+'</div><div style="font-size:9px;color:var(--tx-faint);">Vente</div></div>'
      +'</div>'
      +'<div style="background:var(--br-soft);border-radius:4px;height:6px;overflow:hidden;margin-top:10px;">'
      +'<div style="width:'+vd.pct+'%;height:6px;background:linear-gradient(90deg,var(--green),#44dd99);border-radius:4px;"></div>'
      +'</div></div>'
      +'</div>';
  }

  /* 5. Mettre à jour le panel Fondamentaux (#an-fund) */
  var fundPanel = document.getElementById('an-fund');
  if (fundPanel) {
    var f = d.fund;
    fundPanel.innerHTML =
      '<div style="display:flex;flex-direction:column;gap:6px;">'
      /* VALORISATION */
      +'<div class="card" style="padding:12px;">'
      +'<div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:var(--orange);font-family:var(--mono);font-weight:700;margin-bottom:10px;">VALORISATION</div>'
      +'<div style="font-size:11px;font-family:var(--mono);">'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">P/E Ratio</span><span style="font-weight:700;">'+f.pe+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">PEG Ratio</span><span '+_renderSignalClass(f.pegc)+'>'+f.peg+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">P/B Ratio</span><span>'+f.pb+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;"><span style="color:var(--tx-muted);">Market Cap</span><span style="font-weight:700;">'+f.mc+'</span></div>'
      +'</div></div>'
      /* PERFORMANCE */
      +'<div class="card" style="padding:12px;">'
      +'<div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:var(--orange);font-family:var(--mono);font-weight:700;margin-bottom:10px;">PERFORMANCE</div>'
      +'<div style="font-size:11px;font-family:var(--mono);">'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">EPS (BPA)</span><span '+_renderSignalClass(f.epsc)+'>'+f.eps+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">Revenue</span><span '+_renderSignalClass(f.revc)+'>'+f.rev+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">Marge Nette</span><span '+_renderSignalClass(f.margec)+'>'+f.marge+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;"><span style="color:var(--tx-muted);">ROE</span><span '+_renderSignalClass(f.roec)+'>'+f.roe+'</span></div>'
      +'</div></div>'
      /* RISQUE */
      +'<div class="card" style="padding:12px;">'
      +'<div style="font-size:9px;letter-spacing:2px;text-transform:uppercase;color:var(--orange);font-family:var(--mono);font-weight:700;margin-bottom:10px;">RISQUE</div>'
      +'<div style="font-size:11px;font-family:var(--mono);">'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">Beta</span><span style="color:'+f.betac+';">'+f.beta+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--br-faint);"><span style="color:var(--tx-muted);">52S Haut</span><span>'+f.hi52+'</span></div>'
      +'<div style="display:flex;justify-content:space-between;padding:5px 0;"><span style="color:var(--tx-muted);">52S Bas</span><span>'+f.lo52+'</span></div>'
      +'</div></div>'
      +'</div>';
  }

  /* 6. Mettre à jour le panel News (#an-news) */
  var newsPanel = document.getElementById('an-news');
  if (newsPanel && d.news) {
    var newsHtml = '<div class="news-feed" style="gap:0;">';
    d.news.forEach(function(n) {
      newsHtml += '<div class="news-item" style="border-left:3px solid '+n.col+';padding:8px 10px;">'
        +'<div class="news-src" style="color:'+n.col+';font-size:9px;">'+n.src+'</div>'
        +'<div class="news-title" style="font-size:11px;">'+n.title+'</div>'
        +'<div class="news-time">'+n.time+'</div>'
        +'</div>';
    });
    newsHtml += '</div>';
    newsPanel.innerHTML = newsHtml;
  }
}
